36:     private static final Logger log = LoggerFactory.getLogger(Connect.class);
37: 
38:     private final H herder;
39:     private Future<?> herderTask;
40:     private final ConnectRestServer rest;
41:     private final CountDownLatch startLatch = new CountDownLatch(1);
42:     private final CountDownLatch stopLatch = new CountDownLatch(1);
43:     private final AtomicBoolean shutdown = new AtomicBoolean(false);
44:     private final ShutdownHook shutdownHook;
45: 
46:     public Connect(H herder, ConnectRestServer rest) {
47:         log.debug("Kafka Connect instance created");
48:         this.herder = herder;
49:         this.rest = rest;
50:         shutdownHook = new ShutdownHook();
51:     }
52: 
53:     /**
54:      * Track task status which have been submitted to work thread.
55:      * @return {@link DistributedHerder#herderTask} to track status or null if the herder type doesn't have a separate work thread
56:      */
57:     public Future<?> herderTask() {
58:         return this.herderTask;
59:     }
60: 
61:     public H herder() {
62:         return herder;
63:     }
64: 
65:     public void start() {
66:         try {
67:             log.info("Kafka Connect starting");
68:             Exit.addShutdownHook("connect-shutdown-hook", shutdownHook);
69: 
70:             herder.start();
71:             rest.initializeResources(herder);
72: 
73:             if (herder instanceof DistributedHerder) {
74:                 herderTask = ((DistributedHerder) herder).herderTask();
75:             }
76: 
77:             log.info("Kafka Connect started");
78:         } finally {
79:             startLatch.countDown();
80:         }
81:     }
82: 
83:     public void stop() {
84:         try {
85:             boolean wasShuttingDown = shutdown.getAndSet(true);
86:             if (!wasShuttingDown) {
87:                 log.info("Kafka Connect stopping");
88: 
89:                 rest.stop();
90:                 herder.stop();
91: 
92:                 log.info("Kafka Connect stopped");
93:             }
94:         } finally {
95:             stopLatch.countDown();
96:         }
97:     }
98: 
99:     public void awaitStop() {
100:         try {
101:             stopLatch.await();
102:         } catch (InterruptedException e) {
103:             log.error("Interrupted waiting for Kafka Connect to shutdown");
104:         }
105:     }
106: 
107:     // Visible for testing
108:     public RestServer rest() {
109:         return rest;
110:     }
111: 
112:     private class ShutdownHook extends Thread {
113:         @Override
114:         public void run() {
115:             try {
116:                 startLatch.await();
117:                 Connect.this.stop();
118:             } catch (InterruptedException e) {
119:                 log.error("Interrupted in shutdown hook while waiting for Kafka Connect startup to finish");
120:             }
121:         }
122:     }
123: }
